noteContentFormat:
{% set article_title = selector:.Post-Title|first ?? title|replace:" - 知乎":"" %}
{% set author_name = selector:.AuthorInfo .UserLink-link|last ?? author %}
{% set author_url = selector:.AuthorInfo .UserLink-link?href|last %}
{% set updated_meta = selector:meta[itemprop="dateModified"]?content %}
{% set time_text = selector:.ContentItem-time|first ?? updated_meta %}
{% set upvotes = selector:button.VoteButton|first|replace:"/\D+/g":"" %}
{% set comments = selector:meta[itemprop="commentCount"]?content %}
{% set article_html = selectorHtml:.Post-RichTextContainer|replace_tags:"a":"span"|remove_html:"svg"|replace:"/<p[^>]*>\s*<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>(?:(?!<\\/p>)[\\s\\S])*?<\\/span><\\/span><\\/span>\s*<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>(?:(?!<\\/p>)[\\s\\S])*?<\\/span><\\/span><\\/span>\s*<\\/p>/g":"\n\n@@DISPLAY@@$1@@ENDDISPLAY@@\n\n@@DISPLAY@@$2@@ENDDISPLAY@@\n\n"|replace:"/<p[^>]*>\s*<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>(?:(?!<\\/p>)[\\s\\S])*?<\\/span><\\/span><\\/span>\s*<\\/p>/g":"\n\n@@DISPLAY@@$1@@ENDDISPLAY@@\n\n"|replace:"/<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>[\\s\\S]*?<\\/span><\\/span><\\/span>/g":"@@INLINE@@$1@@ENDINLINE@@"|remove_tags:"span" %}
{% set article_markdown = article_html|markdown|replace:"/@@DISPLAY@@([\\s\\S]*?)@@ENDDISPLAY@@/g":"\n\n$$$$\n$1\n$$$$\n\n"|replace:"/@@INLINE@@([\\s\\S]*?)@@ENDINLINE@@/g":"$$$1$$"|replace:"&amp;":"&" %}
# {{article_title}}

> [!info] 知乎文章
> 作者: {% if author_url %}[{{author_name}}]({{author_url}}){% else %}{{author_name}}{% endif %}
> 原文: [{{url}}]({{url}})
> 时间: {{time_text|replace:"・.*$":""|replace:"T":" "|replace:".000Z":" UTC"}}
{% if upvotes or comments %}> 赞同: {{upvotes ?? "0"}} | 评论: {{comments ?? "0"}}
{% endif %}
## 正文

{{article_markdown}}

{% if highlights %}
## 高亮

{{highlights|fragment_link:"回到原文"|join:"\n\n"}}
{% endif %}
